5</a67><a68>false</a68></ppon><row1 cat="sql"><a1>Task1</a1><a2><l0>select a.createdon, case transtype when  ''ts'' then ''Form''</l0><l1>when ''iv'' then ''Iview''</l1><l2>when ''rsiv'' then ''Responsibility''</l2><l3>when ''rl'' then ''User roles''</l3><l4>when ''wf'' then ''Workflow''</l4><l5>when ''cd'' then ''AxCards''</l5><l6>when ''pg'' then ''Pages''</l6><l7>when ''fr'' then ''Fast report''  end transtype,</l7><l8>coalesce(case transtype when  ''ts'' then t.caption</l8><l9>when ''iv'' then i.caption</l9><l10>when ''rsiv'' then ''Responsibility''</l10><l11>when ''rl'' then ''User roles''</l11><l12>when ''wf'' then ''Workflow''</l12><l13>when ''cd'' then ''AxCards''</l13><l14>when ''pg'' then pg.caption </l14><l15>when ''fr'' then ''Fast report''  end,a.transid) transid,</l15><l16>publishedon,publishedto,status,remarks</l16><l17>from axpublishreport a</l17><l18>left join tstructs t on a.transid = t.name</l18><l19>left join iviews i on a.transid = i.name</l19><l20>left join axpages pg on a.transid = pg.name</l20><l21>where cast(a.createdon as date) = :pdate </l21><l22>and coalesce(publishedby,''NA'') = :ppby </l22><l23>and coalesce(publishedto,''NA'') = :ppon</l23><l24>order by a.createdon desc,transid</l24></a2><a3></a3><a4>reportsql</a4></row1></root>', '1', '01/05/2021 07:31:03', '29/04/2021 13:15:55', '26-06-2025 14:39:45', 'admin', 'admin', 'admin', NULL, NULL),
