ta from SQL'',''SQL Result'') then ''SQL'' end||''| Print forms: ''||a.axprintformnames||''| Download location:''||axprintsaveto||</l9><l10>''| Total records: ''|| a.totallines ||''| Success :''||a.succlines adetails,</l10><l11>status,2,''View details'' actn,''iprnfail'' ptransid,substring(context,7) jobid</l11><l12> from axprintdetails a</l12><l13>left join tstructs b on a.axprinttransid =b.name</l13><l14>left join iviews i on a.axprintiviewname = i.name</l14><l15>where substring(context,7) = :pjobid </l15><l16>union all</l16><l17>select calledon , act_script_name , emaildefname,''Total records: ''|| e.totallines ||''| Success :''||e.succlines ,status,3,''View details'' actn,</l17><l18>''iemlexcp'' ptransid,e.id jobid</l18><l19>from emaildetails e</l19><l20>where substring(context,7) = :pjobid </l20><l21>union all</l21><l22>select starttime,null act_script_name,null apidefname,</l22><l23>''URL :''||url||'' | Service name:''||servicename ||'' | Method: ''||method adetails </l23><l24>,status,4,''View details'' actn,''iaxapilog'' ptransid,a.schjobid jobid</l24><l25> from axapijobdetails a </l25><l26>where jobid = :pjobid </l26><l27>order by ord,jobdate desc</l27></a2><a3></a3><a4>reportsql</a4></row1></root>', '1', '16/04/2021 11:16:32', '16/04/2021 07:19:00', '26-06-2025 14:39:46', 'admin', 'admin', 'admin', NULL, NULL),
