nsid) a2 on a1.htmlsectionsid=a2.htmlsectionsid</l3><l4>left join ( select count(cc)|| '' Image,'' as cntimg,htmlsectionsid from ( </l4><l5>SELECT regexp_split_to_table(axpfile_hpimages, '','') as cc,htmlsectionsid FROM htmlsections where coalesce(axpfile_hpimages,'''')&lt;&gt;'''') as c</l5><l6>GROUP by htmlsectionsid ) d on a1.htmlsectionsid =d.htmlsectionsid </l6><l7>order by a1.createdon desc</l7></a2><a3></a3><a4>reportsql</a4></row1></root>', '1', '16/04/2021 17:16:04', '05/02/2021 18:37:36', '26-06-2025 14:39:46', 'admin', 'shital', 'admin', NULL, NULL),
