e</a3><a1>Task1</a1><a4>Character</a4><a5>0</a5><a6></a6><a7>False</a7><a8>True</a8><a21>True</a21><a13>False</a13><a10>True</a10><a11>False</a11><a12>clWindow</a12><a9>[Arial,8,clBlack,,False,False,False,False]</a9><a14>Left</a14><a15>True</a15><a16>False</a16><a17>80</a17><a18></a18><a19>False</a19><a53></a53><a54></a54><a55></a55><a58></a58><a59></a59><a61>0</a61><a62></a62><a22/></name><row1 cat="sql"><a1>Task1</a1><a2><l0>select null dmy,b.fname ,b.caption  fcaption,a.caption ,a.name,a.runtimetstruct,a.runtimemod </l0><l1>from tstructs a,axpflds b</l1><l2>where a.name = b.tstruct </l2><l3>and a.runtimemod=''T''</l3><l4>and b.runtimefld=''T''</l4><l5>order by 3,2</l5></a2><a3></a3><a4>reportsql</a4></row1></root>', '1', '20/06/2023 11:04:53', '18/10/2022 18:12:18', '26-06-2025 14:40:08', 'admin', 'admin', 'admin', NULL, NULL),
('ad___ups', 'Role permissions', '<root pform="yes" name="ad___ups" caption="Role permissions" updatedon="11/02/2026 16:54:23" updatedby="admin" updusername="" dbtype="postgre" importedon="27/02/2026 16:47:14" importedby="admin" createdon="" createdby=""><iview cat="iview" hideprojname="" hidereportdate="" parrange="1"><a0>ad___ups</a0><a2>Role permissions</a2><a3 ptable=""></a3><a4>0</a4><a5>true</a5><a6></a6><a7></a7><a8>0</a8><a9></a9><a10>false</a10><a11>false</a11><a12></a12><a13></a13><a14></a14><a15></a15><a16></a16><a17>Enabled</a17><a18>false</a18><a19>false</a19><a51></a51><a52></a52><a53></a53><a54></a54><a55>select row</a55><a57>false</a57><a63>true</a63><a64>false</a64><b9>ad___ups</b9><b10></b10><b11></b11><b12></b12><b13></b13><b14></b14><b15></b15><b16></b16><b17></b17><b35>false</b35><b36>Center</b36><b37>Center</b37><a31></a31><a32>1</a32><a33>false</a33><a34>false</a34><a35>0</a35><a36></a36><a37></a37><a38></a38><a39>false</a39><a40>false</a40><a21>false</a21><a41>false</a41><a42>clskyblue</a42><a43>[Tahoma,9,clBlack,,True,False,False,False]</a43><a44>[Tahoma,8,clBlack,,True,False,False,False]</a44><a45>[Tahoma,8,clBlack,,True,False,False,False]</a45><a46>$00F3AFA0</a46><a47>[Tahoma,8,clBlack,,True,False,False,False]</a47><a48>$00EEF1F2</a48><a49>$00E2E8E9</a49><a50>18</a50><a60>1</a60><b18></b18><b21></b21><b23></b23><b22>0</b22><b38>Classic</b38><b39>None</b39><a65>false</a65><a66>false</a66></iview><scripts cat="actions"><aperm script="true" cap="add permission" type="iview" apply="" applyon="" sname="ad___ups" desc="" failmessage="" validate="no" web="no" breakonerror="no" localnum="6"><r1 id="a1" op="5" task="scripts" type="" sname="" apply="" applyon=""><param1 task="scripts" op="7"><exprset><l0>if axpermissionsid &gt; 0 </l0><l1>LoadFormAndData({a__up},{axpermissionsid=:axpermissionsid},{d},{false})</l1><l2>else</l2><l3>LoadForm({a__up},{axuserrole=:groupname~fromsource=:psource~comptype=:comptype~formcap=:capui},{d},{false})</l3><l4>end</l4></exprset></param1></r1></aperm></scripts><comps cat="comps" LocalNum="9" btn="6" vupd="" pnlheight="0"><btn1 caption="" cat="btn" tlhw="7,1,20,20" parent="btnPanel" font="Tahoma,8,clWindowText,ffff" def="right" task="print" action="" container="" sname="" flat="true" position="Left" img="print.bmp" hint="Print" down=""/><btn2 caption="" cat="btn" tlhw="7,1,20,20" parent="btnPanel" font="Tahoma,8,clWindowText,ffff" def="right" task="preview" action="" container="" sname="" flat="true" position="Left" img="preveiw.bmp" hint="Preview" down=""/><btn3 caption="" cat="btn" tlhw="7,1,20,20" parent="btnPanel" font="Tahoma,8,clWindowText,ffff" def="right" task="printersetting" action="" container="" sname="" flat="true" position="Left" img="printersetting.bmp" hint="Page Setup / Printer Setting" down=""/><btn4 caption="" cat="btn" tlhw="7,1,20,20" parent="btnPanel" font="Tahoma,8,clWindowText,ffff" def="right" task="view" action="" container="" sname="" flat="true" position="Left" img="view.bmp" hint="View" down=""/><btn5 caption="" cat="btn" tlhw="7,1,20,20" parent="btnPanel" font="Tahoma,8,clWindowText,ffff" def="right" task="find" action="" container="" sname="" flat="true" position="Left" img="find.bmp" hint="Find" down=""/><btn6 caption="" cat="btn" tlhw="7,1,20,20" parent="btnPanel" font="Tahoma,8,clWindowText,ffff" def="right" task="tasks" action="" container="" sname="" flat="true" position="Left" img="tasks.bmp" hint="Tasks" down=""/><x__head caption="Pemission setups" cat="txt" tlhw="7,5,24,75" parent="pnlButton" font="Tahoma,12,clWindowText,tfff" def="left" type="" align="none" color=""/></comps><row1 cat="sql"><a1>Task1</a1><a2><l0>select  a.axpermissionsid,b.groupname, coalesce(b.caption,b.sname) formcap,coalesce(a.allowcreate,''Yes'') allowcreate,</l0><l1>coalesce(a.viewdlts,''All'')viewdlts,coalesce(editdlts,''All'') editdlts,</l1><l2>b.sname,concat(b.caption,''-('',b.sname,'')'') capui,''Form'' comptype,b.stype,</l2><l3>case b.stype when ''t'' then ''Form'' when ''i'' then ''Report'' when ''p'' then ''Page'' else null end stypeui,</l3><l4>case when b.stype=''t'' then ''aperm,Add permission,script,build_circle'' end AxRowOptions,</l4><l5>case when b.stype=''t'' then ''Configure'' end perm</l5><l6>from (</l6><l7>select  b.axpermissionsid recordid,b.axpermissionsid,b.axusername ,b.axuserrole ,b.formcap,coalesce(b.allowcreate,''Yes'') allowcreate,</l7><l8>	case b.viewctrl when ''0'' then ''All'' </l8><l9>	when ''1'' then ''View these fields - ''||view_flds </l9><l10>	when ''2'' then ''View exclude these fields - ''||view_flds </l10><l11>	when ''4'' then ''No access'' else ''All'' end viewdlts,	</l11><l12>	case b.editctrl when ''0'' then ''All'' </l12><l13>	when ''1'' then ''Edit these fields - ''||edit_flds </l13><l14>	when ''2'' then ''Edit exclude these fields ''||edit_flds</l14><l15>	when ''4'' then ''No access'' else ''All'' end editdlts ,b.formtransid 	</l15><l16>from  axpermissions b where  b.axuserrole =:prole and ''Form'' =b.comptype)a</l16><l17>right join (select distinct sname,caption,groupname,stype from vw_username_role_menu_access where groupname=:prole</l17><l18>and (stype =case :pstype when ''Form'' then ''t'' when ''Report'' then ''i'' when ''Page'' then ''p'' end or ''All'' = :pstype)) b on </l18><l19>b.sname = a.formtransid </l19><l20>union all</l20><l21>select a.axpermissionsid,:prole, b.sqlname formcap,''NA'' allowcreate,</l21><l22>coalesce(a.viewdlts,''All'')viewdlts,''NA'' editdlts,</l22><l23>sqlname sname,sqlname capui,''ADS'' comptype,null stype,''ADS'' stypeui,</l23><l24>''aperm,Setup permission,script,build_circle'' AxRowOptions,''Configure'' perm from</l24><l25>(</l25><l26>select  p.axpermissionsid recordid, p.axpermissionsid,p.axusername,axuserrole groupname, p.formcap,</l26><l27>case p.viewctrl when ''0'' then ''All'' </l27><l28>	when ''1'' then ''View these fields - ''||view_flds </l28><l29>	when ''2'' then ''View exclude these fields - ''||view_flds </l29><l30>	when ''4'' then ''No access'' else ''All'' end viewdlts</l30><l31>from axpermissions p </l31><l32>where  p.comptype =''ADS'' and p.axuserrole = :prole)a</l32><l33>right join(select sqlname from axdirectsql)b on a.formcap=b.sqlname</l33><l34>where (:pstype =''ADS'' or ''All'' = :pstype)</l34><l35>order by 4</l35></a2><a3></a3><a4>reportsql</a4></row1><prole cat="params" ord="1"><a1>Task1</a1><a0>prole</a0><a2>prole</a2><a4>Character</a4><a9>false</a9><a6 sugg="false">{All}</a6><a10></a10><a21>true</a21><a11></a11><a5>0</a5><a12>true</a12><a14>false</a14><a56></a56><a13>Accept</a13><a15></a15><a67>325</a67><a68>false</a68></prole><psource cat="params" ord="2"><a1>Task1</a1><a0>psource</a0><a2>psource</a2><a4>Character</a4><a9>false</a9><a6 sugg="false"></a6><a10></a10><a21>true</a21><a11></a11><a5>0</a5><a12>false</a12><a14>false</a14><a56>R</a56><a13>Accept</a13><a15></a15><a67>325</a67><a68>false</a68></psource><pstype cat="params" ord="3"><a1>Task1</a1><a0>pstype</a0><a2>Menu type</a2><a4>Character</a4><a9>false</a9><a6 sugg="false"></a6><a10></a10><a21>false</a21><a11>select cnd,ord from 
(select ''All'' cnd,1 ord from dual
union all
select ''Form'' cnd,2 ord from dual
union all
select ''Report'' cnd,3 ord from dual
union all
select ''Pages'' cnd,4 ord from dual
union all
select ''ADS'' cnd,5 ord from dual
