>Task1</a1><a4>Character</a4><a5>0</a5><a6></a6><a7>False</a7><a8>True</a8><a21>False</a21><a13>False</a13><a10>True</a10><a11>False</a11><a12>clWindow</a12><a9>[Arial,8,clBlack,,False,False,False,False]</a9><a14>Left</a14><a15>True</a15><a16>False</a16><a17>287</a17><a18></a18><a19>False</a19><a53></a53><a54></a54><a55></a55><a58></a58><a59></a59><a61>0</a61><a62></a62><a22></a22></caption><keysize cat="querycol"><a2>keysize</a2><a3>keysize</a3><a1>Task1</a1><a4>Character</a4><a5>0</a5><a6></a6><a7>False</a7><a8>True</a8><a21>True</a21><a13>False</a13><a10>True</a10><a11>False</a11><a12>clWindow</a12><a9>[Arial,8,clBlack,,False,False,False,False]</a9><a14>Left</a14><a15>True</a15><a16>False</a16><a17>90</a17><a18></a18><a19>False</a19><a53></a53><a54></a54><a55></a55><a58></a58><a59></a59><a61>0</a61><a62></a62><a22></a22></keysize><totalkeys cat="querycol"><a2>totalkeys</a2><a3>Total keys</a3><a1>Task1</a1><a4>Numeric</a4><a5>0</a5><a6></a6><a7>False</a7><a8>True</a8><a21>False</a21><a13>False</a13><a10>True</a10><a11>False</a11><a12>clWindow</a12><a9>[Arial,8,clBlack,,False,False,False,False]</a9><a14>Center</a14><a15>True</a15><a16>False</a16><a17>84</a17><a18></a18><a19>False</a19><a53></a53><a54></a54><a55></a55><a58></a58><a59></a59><a61>0</a61><a62></a62><a22></a22></totalkeys><keys cat="querycol"><a2>keys</a2><a3>keys</a3><a1>Task1</a1><a4>Character</a4><a5>0</a5><a6></a6><a7>False</a7><a8>True</a8><a21>True</a21><a13>False</a13><a10>True</a10><a11>False</a11><a12>clWindow</a12><a9>[Arial,8,clBlack,,False,False,False,False]</a9><a14>Left</a14><a15>True</a15><a16>False</a16><a17>473</a17><a18></a18><a19>False</a19><a53></a53><a54></a54><a55></a55><a58></a58><a59></a59><a61>0</a61><a62></a62><a22></a22></keys><hyperlinks cat="hyperlinks"/><ptasks cat="ptasks"/><row1 cat="sql"><a1>Task1</a1><a2><l0>  SELECT  distinct name AS TName, ftype,  CASE</l0><l1>                         WHEN ftype = ''General'' THEN caption</l1><l2>                         WHEN ftype = ''ALL'' THEN caption</l2><l3>                         ELSE caption</l3><l4>                      END</l4><l5>                         AS caption, TotalKeys, keysize, keys</l5><l6>    FROM (SELECT  distinct name, caption, ''Form'' ftype, ''0'' TotalKeys, ''0'' keysize, ''keys'' keys</l6><l7>            FROM tstructs</l7><l8>           WHERE (:fldtype = ''Tstructs'' OR :fldtype = ''ALL'')</l8><l9>                 AND (caption = :cap OR :cap = ''ALL'')</l9><l10>          UNION</l10><l11>          SELECT  distinct i.name, i.caption, ''Report/List'' AS ftype, ''0'' TotalKeys, ''0'' keysize, ''keys'' keys</l11><l12>            FROM iviews i</l12><l13>           WHERE (:fldtype = ''Iviews'' OR :fldtype = ''ALL'')</l13><l14>                 AND (caption = :cap OR :cap = ''ALL'')</l14><l15></l15><l16>) a</l16><l17>ORDER BY ftype</l17></a2><a3></a3><a4>reportsql</a4></row1><fldtype cat="params" ord="1"><a1>Task1</a1><a0>fldtype</a0><a2>Form Type</a2><a4>Character</a4><a9>False</a9><a6 sugg="false">{ALL}</a6><a10></a10><a21>false</a21><a11>SELECT ''ALL'' AS ftype 
FROM   dual 
UNION 
SELECT ''General'' AS ftype 
FROM   dual 
UNION 
SELECT ''Form'' AS ftype 
FROM   dual 
UNION 
SELECT ''Report/List'' AS ftype 
FROM   dual</a11><a5>0</a5><a12>False</a12><a14>False</a14><a56></a56><a13>Select</a13><a15><s>cap</s></a15><a67>325</a67><a68>false</a68></fldtype><cap cat="params" ord="2"><a1>Task1</a1><a0>cap</a0><a2>Form</a2><a4>Character</a4><a9>False</a9><a6 sugg="false">{ALL}</a6><a10></a10><a21>false</a21><a11 pcount="1"> SELECT distinct CASE
            WHEN ftype = ''General'' THEN caption
            WHEN ftype = ''ALL'' THEN caption
            ELSE caption
         END
            AS caption,2 as slno
    FROM (SELECT NAME, caption, ''Form'' ftype
            FROM tstructs
           WHERE (:fldtype = ''Form'' OR :fldtype = ''ALL'')
          UNION
          SELECT i.NAME, i.caption, ''Report/List'' AS ftype
            FROM iviews i
           WHERE (:fldtype = ''Report/List'' OR :fldtype = ''ALL'')
      )

 a union all
select case when :fldtype = ''General''  then ''General'' else ''ALL'' end as a,1 as slno from dual  
ORDER BY slno,caption</a11><a5>0</a5><a12>False</a12><a14>False</a14><a56></a56><a13>Select</a13><a15/><a67>325</a67><a68>false</a68></cap></root>', '1', '27/06/2019 18:37:54', '13/06/2019 00:00:00', '26-06-2025 14:40:20', 'admin', 'admin', 'admin', NULL, NULL),
