('ad___url', 'User roles', '<root pform="yes" name="ad___url" caption="User roles" updatedon="11/02/2026 17:06:58" updatedby="admin" updusername="" dbtype="postgre" importedon="27/02/2026 16:47:16" importedby="admin" createdon="" createdby=""><iview cat="iview" hideprojname="F" hidereportdate="" parrange="1"><a0>ad___url</a0><a2>User roles</a2><a3 ptable="axpdef_userroles">ad_ur</a3><a4>0</a4><a5>true</a5><a6></a6><a7></a7><a8>0</a8><a9></a9><a10>false</a10><a11>false</a11><a12></a12><a13></a13><a14></a14><a15></a15><a16></a16><a17>Enabled</a17><a18>false</a18><a19>false</a19><a51></a51><a52></a52><a53></a53><a54></a54><a55>select row</a55><a57>false</a57><a63>true</a63><a64>false</a64><b9>ad___url</b9><b10></b10><b11></b11><b12></b12><b13></b13><b14></b14><b15></b15><b16></b16><b17></b17><b35>false</b35><b36>Center</b36><b37>Center</b37><a31></a31><a32>1</a32><a33>false</a33><a34>false</a34><a35>0</a35><a36></a36><a37></a37><a38></a38><a39>false</a39><a40>false</a40><a21>false</a21><a41>false</a41><a42>clskyblue</a42><a43>[Tahoma,9,clBlack,,True,False,False,False]</a43><a44>[Tahoma,8,clBlack,,True,False,False,False]</a44><a45>[Tahoma,8,clBlack,,True,False,False,False]</a45><a46>$00F3AFA0</a46><a47>[Tahoma,8,clBlack,,True,False,False,False]</a47><a48>$00EEF1F2</a48><a49>$00E2E8E9</a49><a50>18</a50><a60>1</a60><b18></b18><b21></b21><b23></b23><b22>0</b22><b38>Classic</b38><b39>None</b39><a65>false</a65><a66>false</a66></iview><scripts cat="actions"><avperm script="true" cap="add/view permission" type="iview" apply="Current Row " applyon="" sname="ad___url" desc="" failmessage="" validate="no" web="no" breakonerror="no" localnum="6"><r1 id="a1" op="5" task="scripts" type="" sname="" apply="" applyon=""><param1 task="scripts" op="7"><exprset><l0>if pst ={View} </l0><l1>LoadIView({ad___ups},{prole=:groupname},{d},{false})</l1><l2>else</l2><l3>LoadForm({a__up},{axuserrole=:groupname~fromsource=:psource},{d},{false})</l3><l4>end</l4></exprset></param1></r1></avperm></scripts><comps cat="comps" dwbtb="true" LocalNum="9" btn="3" vupd="" pnlheight="35"><btn1 key="btn7" caption="New" cat="btn" tlhw="7,1,20,20" parent="btnPanel" font="Tahoma,8,clWindowText,ffff" def="right" task="new" action="" container="" sname="" flat="true" position="Left" visible="true" footer="false" hint="New" down=""><icon><text>add</text><addClass>material-icons</addClass></icon></btn1><btn2 key="btn7" caption="New" cat="btn" tlhw="7,1,20,20" parent="btnPanel" font="Tahoma,8,clWindowText,ffff" def="right" task="new" action="" container="" sname="" flat="true" position="Left" visible="true" footer="false" hint="New" down=""><icon><text>add</text><addClass>material-icons</addClass></icon></btn2><btn3 key="btnTask" caption="Tasks" cat="btn" tlhw="7,1,20,20" parent="btnPanel" font="Tahoma,8,clWindowText,ffff" def="right" task="tasks" action="" container="" sname="" flat="true" position="Left" visible="false" footer="false" folder="true" hint="Tasks" down=""><icon><text>fact_check</text><addClass>material-icons</addClass></icon></btn3><x__head caption="User roles" cat="txt" parent="pnlButton" color="$00F2F0F0" align="none" def="left" tlhw="7,5,19,53" font="_Tahoma,,,clWindowText" type="pnl"/></comps><row1 cat="sql"><a1>Task1</a1><a2><l0>select a.groupname,coalesce(case when a.groupname=''default'' then ''default'' else substring(string_agg(case when stype=''t''  then t.caption</l0><l1>when stype =''i'' then i.caption end,'',''),1,150)||''...'' end,''NA'') sname,</l1><l2>case when aur.rolev2=''T'' then ''tad_ur'' else ''taxrol'' end ldtrans,</l2><l3>case when aur.rolev2=''T'' then aur.AXPDEF_USERROLESid else a.axusergroupsid end ldrecid,</l3><l4>ur.ucnt,a.axusergroupsid,case when prm.cnt &gt; 0 then ''View'' else ''Add'' end pst</l4><l5>from axusergroups a </l5><l6>left join axusergroupsdetail a2 on a.axusergroupsid = a2.axusergroupsid </l6><l7>left join AXPDEF_USERROLES aur on a.groupname = aur.AXUSERGROUP</l7><l8>left join axuseraccess u on a2.roles_id = u.rname </l