a11><a12>clWindow</a12><a9>[Arial,8,clBlack,,False,False,False,False]</a9><a14>Left</a14><a15>True</a15><a16>False</a16><a17>180</a17><a18></a18><a19>False</a19><a53></a53><a54></a54><a55></a55><a58></a58><a59></a59><a61>0</a61><a62></a62></errormessage><senton cat="querycol"><a2>senton</a2><a3>Sent on</a3><a1>Task1</a1><a4>Date/Time</a4><a5>0</a5><a6></a6><a7>False</a7><a8>True</a8><a21>False</a21><a13>False</a13><a10>True</a10><a11>False</a11><a12>clWindow</a12><a9>[Arial,8,clBlack,,False,False,False,False]</a9><a14>Left</a14><a15>True</a15><a16>False</a16><a17>110</a17><a18></a18><a19>False</a19><a53></a53><a54></a54><a55></a55><a58></a58><a59></a59><a61>0</a61><a62></a62></senton><row1 cat="sql"><a1>Task1</a1><a2><l0>  SELECT jobid,</l0><l1>         jobdate,</l1><l2>         mailto,</l2><l3>         mailcc,</l3><l4>         subject,</l4><l5>         SUBSTR (body, 1, 80) || ''...'' AS body,</l5><l6>         senton,</l6><l7>         CASE</l7><l8>            WHEN status = 1 THEN ''Success''</l8><l9>            WHEN status = 0 THEN ''Pending''</l9><l10>            ELSE errormessage</l10><l11>         END</l11><l12>            errormessage</l12><l13>    FROM axp_mailjobs</l13><l14>   WHERE (mailto IS NOT NULL OR mailto &lt;&gt; '''') AND jobdate = :asondate</l14><l15>         AND (UPPER (subject) LIKE ''%'' || UPPER (:psubject) || ''%''</l15><l16>              OR UPPER (:psubject) = ''ALL'')</l16><l17>         AND ( (CASE</l17><l18>                   WHEN status = 1 THEN ''SUCCESS''</l18><l19>                   WHEN status = 0 THEN ''PENDING''</l19><l20>                   ELSE ''FAILURE''</l20><l21>                END) = UPPER (:pstatus)</l21><l22>              OR UPPER (:pstatus) = ''ALL'')</l22><l23>         AND ( (CASE</l23><l24>                   WHEN iviewname IS NOT NULL THEN ''Report''</l24><l25>                   WHEN transid IS NOT NULL THEN ''Document''</l25><l26>                   ELSE ''Alert''</l26><l27>                END) = :petype)</l27><l28>         AND mailto IS NOT NULL</l28><l29>         AND subject IS NOT NULL</l29><l30>         AND mailto &lt;&gt; ''''</l30><l31>         AND subject &lt;&gt; ''''</l31><l32>ORDER BY jobid</l32></a2><a3></a3><a4>reportsql</a4></row1><asondate cat="params" ord="1"><a1>Task1</a1><a0>asondate</a0><a2>As on Date</a2><a4>Date/Time</a4><a9>False</a9><a6 sugg="false"></a6><a10></a10><a21>false</a21><a11>select date(current_date) sysdt from dual</a11><a5>0</a5><a12>False</a12><a14>False</a14><a56></a56><a13>Accept</a13><a15/><a67>325</a67><a68>false</a68></asondate><psubject cat="params" ord="2"><a1>Task1</a1><a0>psubject</a0><a2>Subject Contains</a2><a4>Character</a4><a9>False</a9><a6 sugg="false"></a6><a10></a10><a21>false</a21><a11></a11><a5>0</a5><a12>False</a12><a14>False</a14><a56>ALL</a56><a13>Accept</a13><a15/></psubject><pstatus cat="params" ord="3"><a1>Task1</a1><a0>pstatus</a0><a2>Status</a2><a4>Character</a4><a9>False</a9><a6 sugg="false"></a6><a10></a10><a21>false</a21><a11>select ''PENDING'' status from dual 
