union all 
select ''Alert'' etype from dual 
order by 1</a11><a5>0</a5><a12>False</a12><a14>False</a14><a56></a56><a13>Select</a13><a15/><a67>325</a67><a68>false</a68></petype></root>', '1', '21/10/2021 16:54:12', '02/07/2015 12:38:40', '26-06-2025 14:40:33', 'admin', 'admin', 'admin', NULL, NULL),
