</a18><a19>False</a19><a53></a53><a54></a54><a55></a55><a58></a58><a59></a59><a61>0</a61><a62></a62><a22/></recdon><transid cat="querycol"><a2>transid</a2><a3>Transid</a3><a1>Task1</a1><a4>Character</a4><a5>0</a5><a6></a6><a7>False</a7><a8>True</a8><a21>False</a21><a13>False</a13><a10>True</a10><a11>False</a11><a12>clWindow</a12><a9>[Arial,8,clBlack,,False,False,False,False]</a9><a14>Left</a14><a15>True</a15><a16>False</a16><a17>80</a17><a18></a18><a19>False</a19><a53></a53><a54></a54><a55></a55><a58></a58><a59></a59><a61>0</a61><a62></a62><a22/></transid><tstructname cat="querycol"><a2>tstructname</a2><a3>Tstruct Name</a3><a1>Task1</a1><a4>Character</a4><a5>0</a5><a6></a6><a7>False</a7><a8>True</a8><a21>False</a21><a13>False</a13><a10>True</a10><a11>False</a11><a12>clWindow</a12><a9>[Arial,8,clBlack,,False,False,False,False]</a9><a14>Left</a14><a15>True</a15><a16>False</a16><a17>80</a17><a18></a18><a19>False</a19><a53></a53><a54></a54><a55></a55><a58></a58><a59></a59><a61>0</a61><a62></a62><a22/></tstructname><instatus cat="querycol"><a2>instatus</a2><a3>Status</a3><a1>Task1</a1><a4>Character</a4><a5>0</a5><a6></a6><a7>False</a7><a8>True</a8><a21>False</a21><a13>False</a13><a10>True</a10><a11>False</a11><a12>clWindow</a12><a9>[Arial,8,clBlack,,False,False,False,False]</a9><a14>Left</a14><a15>True</a15><a16>False</a16><a17>80</a17><a18></a18><a19>False</a19><a53></a53><a54></a54><a55></a55><a58></a58><a59></a59><a61>0</a61><a62></a62><a22/></instatus><asondt cat="params" ord="1"><a1>Task1</a1><a0>asondt</a0><a2>As on Date</a2><a4>Date/Time</a4><a9>False</a9><a6 sugg="false">date()</a6><a10></a10><a21>false</a21><a11></a11><a5>0</a5><a12>False</a12><a14>False</a14><a56></a56><a13>Accept</a13><a15/></asondt><pstatus cat="params" ord="2"><a1>Task1</a1><a0>pstatus</a0><a2>Status</a2><a4>Character</a4><a9>False</a9><a6 sugg="false"></a6><a10></a10><a21>false</a21><a11>select ''ALL'' pstatus  from dual
union 
select ''Failed'' pstatus from dual
order by pstatus</a11><a5>0</a5><a12>False</a12><a14>False</a14><a56></a56><a13>Accept</a13><a15/></pstatus><ptransid cat="params" ord="3"><a1>Task1</a1><a0>ptransid</a0><a2>Transid</a2><a4>Character</a4><a9>False</a9><a6 sugg="false"></a6><a10></a10><a21>false</a21><a11></a11><a5>0</a5><a12>False</a12><a14>False</a14><a56>ALL</a56><a13>Accept</a13><a15/></ptransid><pfilename cat="params" ord="4"><a1>Task1</a1><a0>pfilename</a0><a2>File Name</a2><a4>Character</a4><a9>False</a9><a6 sugg="false"></a6><a10></a10><a21>false</a21><a11></a11><a5>0</a5><a12>False</a12><a14>False</a14><a56>ALL</a56><a13>Accept</a13><a15/></pfilename><row1 cat="sql"><a1>Task1</a1><a2><l0>  SELECT filename,</l0><l1>         recdon,</l1><l2>         transid,</l2><l3>         tstructname,</l3><l4>         instatus</l4><l5>    FROM ax_inbound_status</l5><l6>   WHERE indate = :asondt</l6><l7>         AND ( (instatus NOT LIKE ''%No of Records not imported : 0%''</l7><l8>                AND :pstatus = ''Failed'')</l8><l9>              OR :pstatus = ''ALL'')</l9><l10>         AND (transid LIKE ''%'' || :ptransid || ''%'' OR :ptransid = ''ALL'')</l10><l11>         AND (filename LIKE ''%'' || :pfilename || ''%'' OR :pfilename = ''ALL'')</l11><l12>ORDER BY recdon DESC</l12></a2><a3></a3><a4>reportsql</a4></row1></root>', '1', '19/06/2019 00:00:00', '02/07/2015 00:00:00', '26-06-2025 14:40:37', 'admin', 'admin', 'admin', NULL, NULL),
