caption,''('',c.fname,'')'')  ccaption, </l10><l11>concat(''&lt;span style="font-weight:bold;"&gt;'',</l11><l12>case when c.runtimefld =''T'' then ''Runtime'' else ''Developer'' end|| ''&lt;br/&gt;'',''Field type - '',''&lt;/span&gt;'', c.customdatatype,''&lt;br/&gt;'',</l12><l13>''&lt;span style="font-weight:bold;"&gt;''||''Data type and Width - '',''&lt;/span&gt;'',concat(case "datatype" when ''c'' then ''Character''  </l13><l14>when ''d'' then ''Date'' when ''i'' then ''Image'' when ''t'' then ''Text'' when ''n'' then ''Numeric'' end,''('',case when datatype=''n'' </l14><l15>then concat(cast(datawidth as varchar(5)),'','',cast(flddecimal as varchar(5))) else cast(datawidth  as varchar(10)) end,'')'' ),''&lt;br/&gt;'') fdesc,</l15><l16>concat(coalesce(case when c.readonly = ''T'' then  ''&lt;span style="font-weight:bold;"&gt;''||''ReadOnly ''||''&lt;/span&gt;&lt;br/&gt;'' || ''''|| ''&lt;br/&gt;'' end,''''),</l16><l17>coalesce(case when c.hidden= ''T'' then ''&lt;span style="font-weight:bold;"&gt;''||''Hidden''||''&lt;/span&gt;&lt;br/&gt;'' ||''''|| ''&lt;br/&gt;'' end,''''),</l17><l18>coalesce(''&lt;span style="font-weight:bold;"&gt;''||case when c.allowempty= ''F'' then ''Mandatory'' else '''' end||''&lt;/span&gt;&lt;br/&gt;'' ||''''|| ''&lt;br/&gt;'' ,''''),</l18><l19>coalesce(case when c.mask is not null then ''&lt;span style="font-weight:bold;"&gt;''||''Mask ''||''&lt;/span&gt;&lt;br/&gt;''|| c.mask||'' &lt;br/&gt;'' end,''''),</l19><l20>coalesce(''&lt;span style="font-weight:bold;"&gt;''||case when c.allowduplicate= ''F'' then ''Unique''||''&lt;/span&gt;&lt;br/&gt;'' ||''''|| ''&lt;br/&gt;'' end ,'''')</l20><l21>) datarule,</l21><l22>concat(coalesce(case when c.expression is not null then ''&lt;span style="font-weight:bold;"&gt;''||''Expression ''||''&lt;/span&gt;&lt;br/&gt;'' || c.expression || ''&lt;br/&gt;'' end,''''),</l22><l23>coalesce(case when c.valexpr is not null then ''&lt;span style="font-weight:bold;"&gt;''||''Validation  ''||''&lt;/span&gt;&lt;br/&gt;'' || c.valexpr || ''&lt;br/&gt;'' end,'' '')) validrule,</l23><l24>c.dcname,c.ordno,2 lord,null editcmd,a.caption||''-(''||a.name||'')'' fparams,</l24><l25>''&lt;b&gt;Created by&lt;/b&gt; ''||c.createdby||'' on ''||c.createdon||''&lt;/br&gt;&lt;b&gt; Last modified by &lt;/b&gt;''||c.modifiedby||'' on ''||c.modifiedon updated,null editcmdtransid,0 editcmdrecid</l25><l26>from tstructs a </l26><l27>join axpflds c on a.name = c.tstruct  </l27><l28>where a.name = :ptransid </l28><l29>union all</l29><l30>select null editable,''Fillgrid'' ctypre,t.name,t.caption, a.fgname,concat(a.caption,''('',a.fgname,'')''),</l30><l31>concat(''&lt;span style="font-weight:bold;"&gt;'',''Target DC - '',''&lt;/span&gt;'' , ''dc''||tardc, ''&lt;br/&gt;'' ,</l31><l32>''&lt;span style="font-weight:bold;"&gt;'',''Data source - '',''&lt;/span&gt;'', case when a.srcdc = ''0'' then ''SQL'' else ''dc''||a.srcdc end,''&lt;br/&gt;'',</l32><l33>''&lt;span style="font-weight:bold;"&gt;'',''Autoshow - '',''&lt;/span&gt;'', case when a.autoshow = ''T'' then ''Yes'' else ''No'' end, ''&lt;br/&gt;'',</l33><l34>''&lt;span style="font-weight:bold;"&gt;'',''Multiselect - '',''&lt;/span&gt;'', case when a.multiselect = ''T'' then ''Yes'' else ''No'' end, ''&lt;br/&gt;''</l34><l35>) as cprops,null,null,''z100'',1,3,null editcmd,t.caption||''-(''||t.name||'')'' fparams,</l35><l36>''&lt;b&gt;Created by&lt;/b&gt; ''||a.createdby||'' on ''||a.createdon||''&lt;/br&gt;&lt;b&gt; Last modified by &lt;/b&gt;''||a.modifiedby||'' on ''||a.modifiedon updated,null editcmdtransid,0 editcmdrecid</l36><l37>from axpfillgrid a join tstructs t on a.tstruct =t.name  and t.name = :ptransid</l37><l38>union all</l38><l39>select null editable,''MDMAP'' ctypre,t.name,t.caption, a.mname,concat(a.caption,''('',a.mname,'')''),</l39><l40> concat(''&lt;span style="font-weight:bold;"&gt;'',''Master form - '',''&lt;/span&gt;'' , mt.caption||''-(''||mt."name"||'')'' , ''&lt;br/&gt;'' ,</l40><l41>''&lt;span style="font-weight:bold;"&gt;'',''Master field - '',''&lt;/span&gt;'',muf.caption||''-(''||muf.fname||'')'' ,''&lt;br/&gt;'',</l41><l42>''&lt;span style="font-weight:bold;"&gt;'',''Detail field - '',''&lt;/span&gt;'',duf.caption||''-(''||duf.fname||'')'' ,''&lt;br/&gt;'',</l42><l43>''&lt;span style="font-weight:bold;"&gt;'',''Master search field -  '',''&lt;/span&gt;'',CASE WHEN msf.fname IS NULL THEN ''Default'' ELSE  coalesce(msf.caption||''-(''||msf.fname||'')'',a.msrcfld) end, ''&lt;br/&gt;'',</l43><l44>''&lt;span style="font-weight:bold;"&gt;'',''Detail search field - '',''&lt;/span&gt;'',coalesce(dsf.caption||''-(''||dsf.fname||'')'',a.dtlsrcfld)</l44><l45>) as cprops,null,null,''z100'',1,4,null editcmd,t.caption||''-(''||t.name||'')'' fparams,</l45><l46>''&lt;b&gt;Created by&lt;/b&gt; ''||a.createdby||'' on ''||a.createdon||''&lt;/br&gt;&lt;b&gt; Last modified by &lt;/b&gt;''||a.modifiedby||'' on ''||a.modifiedon updated,null editcmdtransid,0 editcmdrecid</l46><l47>from axpmdmaps a join tstructs t on a.tstruct =t.name and t.name = :ptransid</l47><l48>join tstructs mt on a.mastrans = mt.name</l48><l49>join axpflds muf on a.masfld = muf.fname and a.mastrans = muf.tstruct </l49><l50>left join axpflds msf on a.msrcfld = msf.fname and a.mastrans = msf.tstruct </l50><l51>join axpflds duf on a.detfld = duf.fname and a.tstruct = duf.tstruct</l51><l52>left join axpflds dsf on a.dtlsrcfld = dsf.fname and a.tstruct = dsf.tstruct</l52><l53>union all</l53><l54>select null editable,''Genmap'',t.name,t.caption fcaption, a.gname,concat(a.caption,''('',a.gname,'')''),</l54><l55>concat(''&lt;span style="font-weight:bold;"&gt;'',''Target form - '',''&lt;/span&gt;'' , tt.caption||''-(''||tt.name||'')'', ''&lt;br/&gt;'' ,</l55><l56>''&lt;span style="font-weight:bold;"&gt;'',''Based on - '',''&lt;/span&gt;'', basedondc,''&lt;br/&gt;'',</l56><l57>''&lt;span style="font-weight:bold;"&gt;'',''Control fieldname'',''&lt;/span&gt;'', a.ctrlfldname , ''&lt;br/&gt;'') as cprops,null,null,''z100'',1,5,null editcmd,</l