se,False]</a9><a14>Left</a14><a15>True</a15><a16>False</a16><a17>120</a17><a18></a18><a19>False</a19><a53></a53><a54></a54><a55></a55><a58></a58><a59></a59><a61>0</a61><a62></a62><a22/></publishedon><dtasks cat="dtasks"></dtasks><actions cat="actions"><test cap="test" type="iview" apply="All Selected Rows" applyon="" sname="axpubls" localnum="2" desc="" failmessage="" validate="no" web="no" breakonerror="no"><r1 id="a1" op="5" task="Scripts" type="" sname="" apply="" applyon=""><param1 task="scripts" op="7"><exprset><l0>@start</l0><l1>tmpvar :=  {}</l1><l2>firesql({s1},{select to_char(now(),''DDDYYYYHHMIMS'') sid from dual})</l2><l3>reqid := sqlget({s1},{sid})</l3><l4></l4><l5></l5><l6></l6><l7>@row  </l7><l8>tmpvar := tmpvar+ pname+{,}</l8><l9></l9><l10>@end </l10><l11>uploadedfiles:=UploadStructures(tmpvar,puloadurl)</l11><l12>request_str:={&lt;x:Envelope xmlns:x="http://schemas.xmlsoap.org/soap/envelope/" xmlns:urn="urn:uAxpertLic-AxpertLic"&gt;&lt;x:Header/&gt;&lt;x:Body&gt;&lt;urn:PublishStructures&gt;&lt;urn:pTargetSchema&gt;}+pschema+{&lt;/urn:pTargetSchema&gt;&lt;urn:pListOfExportedStrcutFileNames&gt;}+uploadedfiles+{&lt;/urn:pListOfExportedStrcutFileNames&gt;&lt;urn:pExportedFilePath&gt;&lt;/urn:pExportedFilePath&gt;&lt;/urn:PublishStructures&gt;&lt;/x:Body&gt;&lt;/x:Envelope&gt;}</l12><l13>ExecuteAPI(reqid,papiurl,{uploadstructure},{post},{},{},request_str)</l13></exprset></param1></r1></test><publish cap="test" type="iview" apply="All Selected Rows" applyon="" sname="axpubls" localnum="1" desc="" failmessage="" validate="no" web="no" breakonerror="no"><r1 id="a1" op="5" task="Scripts" type="" sname="" apply="" applyon=""><param1 task="scripts" op="7"><exprset><l0>@start</l0><l1>tmpvar :=  {}</l1><l2>firesql({s1},{select to_char(now(),''DDDYYYYHHMIMS'') sid from dual})</l2><l3>reqid := sqlget({s1},{sid})</l3><l4></l4><l5></l5><l6></l6><l7>@row  </l7><l8>tmpvar := tmpvar+ pname+{,}</l8><l9></l9><l10>@end </l10><l11>uploadedfiles:=UploadStructures(tmpvar,puloadurl)</l11><l12>request_str:={&lt;x:Envelope xmlns:x="http://schemas.xmlsoap.org/soap/envelope/" xmlns:urn="urn:uAxpertLic-AxpertLic"&gt;&lt;x:Header/&gt;&lt;x:Body&gt;&lt;urn:PublishStructures&gt;&lt;urn:pTargetSchema&gt;}+pschema+{&lt;/urn:pTargetSchema&gt;&lt;urn:pListOfExportedStrcutFileNames&gt;}+uploadedfiles+{&lt;/urn:pListOfExportedStrcutFileNames&gt;&lt;urn:pExportedFilePath&gt;&lt;/urn:pExportedFilePath&gt;&lt;/urn:PublishStructures&gt;&lt;/x:Body&gt;&lt;/x:Envelope&gt;}</l12><l13>ExecuteAPI(reqid,papiurl,{uploadstructure},{post},{},{},request_str)</l13></exprset></param1></r1></publish><pubtosr cap="pubtosr" type="iview" apply="" applyon="" sname="axpubls" localnum="2" desc="" failmessage="" validate="no" web="no" breakonerror="no"><r1 id="a1" op="0" cset="" exprset="ftype -isemptyvalue (ftype  , {})" type="" sname="" apply="" applyon="">ftype Is Empty</r1></pubtosr><listservers cap="listservers" type="iview" apply="" applyon="" sname="axpubls" localnum="2" desc="" failmessage="" validate="no" web="no" breakonerror="no"><r1 id="a1" op="5" task="Open Iview" type="" sname="" apply="" applyon=""><param1 task="open iview" op="7"><visible>True</visible><Refresh>False</Refresh><caption>Servers configuration</caption><showin/><name>pservers</name><fieldvalues/></param1></r1></listservers><addserver cap="addserver" type="iview" apply="" applyon="" sname="axpubls" localnum="2" desc="" failmessage="" validate="no" web="no" breakonerror="no"><r1 id="a1" op="5" task="Open TStruct" type="" sname="" apply="" applyon=""><param1 task="open tstruct" op="7"><name>axpub</name><caption>new server configuration</caption><showin/><visible>True</visible><Refresh>False</Refresh><fieldvalues/></param1></r1></addserver></actions><pname cat="querycol"><a2>pname</a2><a3>pname</a3><a1>Task1</a1><a4>Character</a4><a5>0</a5><a6></a6><a7>False</a7><a8>True</a8><a21>True</a21><a13>False</a13><a10>True</a10><a11>False</a11><a12>clWindow</a12><a9>[Arial,8,clBlack,,False,False,False,False]</a9><a14>Left</a14><a15>True</a15><a16>False</a16><a17>80</a17><a18></a18><a19>False</a19><a53></a53><a54></a54><a55></a55><a58></a58><a59></a59><a61>0</a61><a62></a62><a22/></pname><axpubls><pserver></pserver><purl></purl><pschema></pschema><papiurl></papiurl><puloadurl></puloadurl><pappname></pappname><pdevpublish></pdevpublish></axpubls><objtype cat="querycol"><a2>objtype</a2><a3>objtype</a3><a1>Task1</a1><a4>Character</a4><a5>0</a5><a6></a6><a7>False</a7><a8>True</a8><a21>False</a21><a13>False</a13><a10>True</a10><a11>False</a11><a12>Clwindow</a12><a9>[Arial,8,clBlack,,False,False,False,False]</a9><a14>Left</a14><a15>True</a15><a16>False</a16><a17>80</a17><a18></a18><a19>False</a19><a53></a53><a54></a54><a55></a55><a58></a58><a59></a59><a61>0</a61><a62></a62><a22></a22></objtype><row1 cat="sql"><a1>Task1</a1><a2><l0>select a.*,b.publishedon from </l0><l1>(select distinct ''Tstruct'' ftype,b.name,b.caption,cast(b.updatedon as varchar(30)) updatedon,1 ord,concat(''ts'',name) pname,''Axpert'' objtype  from </l1><l2>tstructs b</l2><l3>union all</l3><l4>select distinct''Iview'' ftype,a.name,a.caption,cast(a.updatedon as varchar(30)) updatedon,2 ord,concat(''iv'',a.name) pname,''Axpert'' objtype from iviews a</l4><l5>union all</l5><l6>select distinct ''Responsibility'',rname,null,cast(updatedon as varchar(30)) updatedon,3 ord,concat(''rs'',rname) pname,''Axpert'' objtype from axuseraccess </l6><l7>union all</l7><l8>select ''Roles'' ftype,groupname,null,null,4 ord,concat(''rl'',groupname) pname,''Axpert'' objtype from axusergroups</l8><l9>union all</l9><l10>select ''Workflow'' ftype,name,caption,cast(updatedon as varchar(30)) updatedon,6 ord,concat(''wf'',name) pname,''Axpert'' objtype from axworkflow</l10><l11>union all</l11><l12>select ''Cards'',cardname,cardtype,cast(modifiedon as varchar(30)) ,7,concat(''cd'',cardname),''Axpert'' objtype from axp_cards</l12><l13>union all</l13><l14>select ''Pages'',name,caption,cast(updatedon as varchar(30)) updatedon,8,concat(''pg'',name),''Axpert'' objtype from axpages</l14><l15>union all</l15><l16>select ''Fast Report'',caption,transid,null updatedon,9,concat(''fr'',caption),''Axpert'' objtype from axfastlink a2 </l16><l17>union all</l17><l18>select ''Jobs'',jobid,jname,cast(modifiedon as varchar(30)) ,10,concat(''sc'',jobid),''Axpert'' objtype from  axpdef_jobs</l18><l19>union all</l19><l20>select ''View'',table_name,null,null,11,concat(''dv'',table_name ),''DB'' objtype from INFORMATION_SCHEMA.views </l20><l21>WHERE table_schema = ANY (current_schemas(false)) </l21><l22>union all</l22><l23>select ''Materialized View'',matviewname,null,null,12,concat(''dv'',matviewname),''DB'' objtype from pg_catalog.pg_matviews pm </l23><l24>WHERE schemaname = ANY (current_schemas(false)) </l24><l25>union all</l25><l26>select ''Function'',a.proname,null,null,13,concat(''df'',proname ),''DB'' objtype from pg_catalog.pg_proc a join pg_catalog.pg_namespace b </l26><l27>on a.pronamespace =b.oid </l27><l28>where b.nspname = ANY (current_schemas(false))</l28><l29>union all </l29><l30>select ''Trigger'',trigger_name ,null,null,14,concat(''dt'',trigger_name ),''DB'' objtype from information_schema.triggers t </l30><l31>WHERE trigger_schema = ANY (current_schemas(false)) </l31><l32>union all </l32><l33>select ''Index'',indexname ,null,null,15,concat(''di'',indexname ),''DB'' objtype from pg_catalog.pg_indexes t </l33><l34>WHERE schemaname = ANY (current_schemas(false)) </l34><l35>union all</l35><l36>select ''Sequence'',sequence_name,null,null,16,concat(''ds'',sequence_name),''DB'' objtype from information_schema."sequences" s</l36><l37>where sequence_schema= ANY (current_schemas(false))</l37><l38>union all</l38><l39>select ''API Definition'',execapidefname,null,null,17,concat(''ap'',execapidefname),''Axpert'' objtype from executeapidef</l39><l40>union all</l40><l41>select ''Import Definition'',aximpdefname,null,null,18,concat(''im'',aximpdefname),''Axpert'' objtype from aximpdef</l41><l42>union all</l42><l43>select ''Email Definition'',emaildefname,null,null,19,concat(''em'',emaildefname),''Axpert'' objtype from emaildef</l43><l44>)a </l44><l45>left join (select transtype||transid transid,max(publishedon) publishedon from axpublishreport where status=''Published'' group by transtype||transid ) b on a.pname = b.transid</l45><l46>where (a.objtype = :pobjtype or ''All'' = :pobjtype)</l46><l47>order by ord,name</l47></a2><a3></a3><a4>reportsql</a4></row1><pserver cat="params" ord="1"><a1></a1><a0>pserver</a0><a2>Server name</a2><a4>Character</a4><a9>False</a9><a6 sugg="false"></a6><a10></a10><a21>false</a21><a11>select servername from dwb_publishprops where servertype=''Publish'' AND INACTIVE=''F'' order by 1</a11><a5>0</a5><a12>True</a12><a14>False</a14><a56></a56><a13>Select</a13><a15><s>papiurl,pappname,pdevpublish</s></a15><a67>325</a67><a68>false</a68></pserver><papiurl cat="params" ord="2"><a1></a1><a0>papiurl</a0><a2>API URL</a2><a4>Character</a4><a9>False</a9><a6 sugg="false"></a6><a10></a10><a21>true</a21><a11 pcount="1">select serverpath from dwb_publishprops where servername = :pserver</a11><a5>0</a5><a12>True</a12><a14>False</a14><a56></a56><a13>Accept</a13><a15/><a67>325</a67><a68>false</a68></papiurl><pappname cat="params" ord="3"><a1></a1><a0>pappname</a0><a2>Connection name</a2><a4>Character</a4><a9>False</a9><a6 sugg="false"></a6><a10></a10><a21>true</a21><a11 pcount="1">select app_connection from dwb_publishprops where servername = :pserver</a11><a5>0</a5><a12>True</a12><a14>False</a14><a56></a56><a13>Accept</a13><a15/><a67>325</a67><a68>false</a68></pappname><pdevpublish cat="params" ord="4"><a1></a1><a0>pdevpublish</a0><a2>Publish to dev</a2><a4>Character</a4><a9>False</a9><a6 sugg="false"></a6><a10></a10><a21>true</a21><a11 pcount="1">select publishtodev from dwb_publishprops where servername = :pserver</a11><a5>0</a5><a12>True</a12><a14>False</a14><a56></a56><a13>Accept</a13><a15/><a67>325</a67><a68>false</a68></pdevpublish><pobjtype cat="params" ord="5"