cat="btn" tlhw="7,1,20,20" parent="btnPanel" font="Tahoma,8,clWindowText,ffff" def="right" task="" action="" container="" sname="" flat="true" position="Left" visible="true" footer="false" hint="Excel" down=""/><btn4 key="btnTask" caption="Tasks" cat="btn" tlhw="7,1,20,20" parent="btnPanel" font="Tahoma,8,clWindowText,ffff" def="right" task="tasks" action="" container="" sname="" flat="true" position="Left" visible="false" footer="false" folder="true" hint="Tasks" down=""><icon><text>fact_check</text><addClass>material-icons</addClass></icon></btn4><x__head caption="User access" cat="txt" parent="pnlButton" color="$00F2F0F0" align="none" def="left" tlhw="7,5,19,53" font="_Tahoma,,,clWindowText" type="pnl"/></comps><row1 cat="sql"><a1>Task1</a1><a2><l0>select name, CAPTION, ''Page'' stype from axpages a2 join axuserlevelgroups a on a.usergroup =''default'' and a.username =:pusername</l0><l1>union</l1><l2>select name, CAPTION, ''Tstruct'' stype from tstructs a2 join axuserlevelgroups a on a.usergroup =''default'' and a.username = :pusername</l2><l3>union</l3><l4>select name, CAPTION, ''Iview'' stype from iviews a2 join axuserlevelgroups a on a.usergroup =''default'' and a.username = :pusername</l4><l5>union</l5><l6>select p.name,p.caption,''Page'' from axusers u join axuserlevelgroups a on u.axusersid=a.axusersid </l6><l7>join axusergroups a2 on a2.groupname = a.axusergroup </l7><l8>join axusergroupsdetail a3 on a2.axusergroupsid =a3.axusergroupsid </l8><l9>join axuseraccess a4 on a4.rname = a3.roles_id and a4.stype=''p'' </l9><l10>join axpages p on a4.sname = p.name </l10><l11>and u.username = :pusername </l11><l12>union</l12><l13>select t.name,t.caption,''Tstruct'' from axusers u join axuserlevelgroups a on u.axusersid=a.axusersid </l13><l14>join axusergroups a2 on a2.groupname = a.axusergroup </l14><l15>join axusergroupsdetail a3 on a2.axusergroupsid =a3.axusergroupsid </l15><l16>join axuseraccess a4 on a4.rname = a3.roles_id and a4.stype=''t'' </l16><l17>join tstructs t on a4.sname = t.name </l17><l18>and u.username = :pusername</l18><l19>union</l19><l20>select i.name,i.caption,''Iview'' from axusers u join axuserlevelgroups a on u.axusersid=a.axusersid </l20><l21>join axusergroups a2 on a2.groupname = a.axusergroup </l21><l22>join axusergroupsdetail a3 on a2.axusergroupsid =a3.axusergroupsid </l22><l23>join axuseraccess a4 on a4.rname = a3.roles_id  and a4.stype=''i''</l23><l24>join iviews i on a4.sname = i.name </l24><l25>and u.username = :pusername</l25><l26>order by caption,stype</l26></a2><a3></a3><a4>reportsql</a4></row1><pusername cat="params" ord="1"><a1>Task1</a1><a0>pusername</a0><a2>pusername</a2><a4>Character</a4><a9>false</a9><a6 sugg="false"></a6><a10></a10><a21>true</a21><a11></a11><a5>0</a5><a12>true</a12><a14>false</a14><a56></a56><a13>Accept</a13><a15></a15><a67>325</a67><a68>false</a68></pusername><name cat="querycol" encrypted="F" freezecol="F" negativenorep="" customdecimal="F"><a2>name</a2><a3>name</a3><a1>Task1</a1><a4>Character</a4><a5>0</a5><a6></a6><a7>false</a7><a8>true</a8><a21>true</a21><a13>false</a13><a10>false</a10><a11>false</a11><a12>Clwindow</a12><a9>[Arial,8,clBlack,,False,False,False,False]</a9><a14>Left</a14><a15>true</a15><a16>false</a16><a17>80</a17><a18></a18><a19>false</a19><a53></a53><a54></a54><a55></a55><a58></a58><a59></a59><a61>0</a61><a62></a62><a69 masking=""></a69></name><caption cat="querycol" encrypted="F" freezecol="F" negativenorep="" customdecimal="F"><a2>caption</a2><a3>Caption</a3><a1>Task1</a1><a4>Character</a4><a5>0</a5><a6></a6><a7>false</a7><a8>true</a8><a21>false</a21><a13>false</a13><a10>false</a10><a11>false</a11><a12>Clwindow</a12><a9>[Arial,8,clBlack,,False,False,False,False]</a9><a14>Left</a14><a15>true</a15><a16>false</a16><a17>398</a17><a18></a18><a19>false</a19><a53></a53><a54></a54><a55></a55><a58></a58><a59></a59><a61>0</a61><a62></a62><a69 masking=""></a69></caption><stype cat="querycol" encrypted="F" freezecol="F" negativenorep="" customdecimal="F"><a2