</l0><l1>concat(case when a.runtimetstruct=''T'' then ''Runtime form'' else ''Developer form'' end||''&lt;/br&gt;'',</l1><l2>case when length(t.purpose) &gt; 3 then purpose||''&lt;/br&gt;'' else '''' end,</l2><l3>(select pr_utl_forms_menutree(concat(''t'',a.name))),</l3><l4>coalesce ( case when length(t.savectrlfld) &gt; 1 then ''Save control field- ''||t.savectrlfld ||''&lt;/br&gt;'' end,''''),</l4><l5>coalesce (case when t.delctrlfld is not null then ''Delete control field- ''|| t.delctrlfld ||''&lt;/br&gt;'' end,''''),</l5><l6>case when coalesce(oq.oqns,0 ) != 0 then  oq.oqns|| '' Outbound queues''||'','' else '''' end,</l6><l7>case when coalesce(b.cnt,0 ) != 0 then  b.cnt ||'' Rules defined''|| '','' else '''' end,</l7><l8>case when coalesce(p.pros,0 ) != 0 then  p.pros||'' Process defined''|| '','' else '''' end,</l8><l9>case when coalesce(ap.aps,0 ) != 0 then  ap.aps||'' Auto prints''||'','' else '''' end,</l9><l10>case when coalesce(fn.fns,0 ) != 0 then  fn.fns||'' Form notifications''||'','' else '''' end)</l10><l11>as form_properties,concat(case when a.runtimetstruct=''T'' then concat(''script3,Edit form,script,edit~'')  else null end,</l11><l12>case when a.runtimemod =''T'' then concat(''ruleeng,'',case when b.cnt&gt;0 then ''View rules'' else ''Add rule'' end,'',script,rule~'') end,</l12><l13>case when p.pros &gt; 0 then concat(''peg,'',''Process listing'','',script,schema~'') else concat(''newpeg,'',''Add process definition'','',script,schema~'') end,</l13><l14>concat(''autoprint,'',case when ap.aps&gt;0 then ''View AutoPrints'' else ''Add AutoPrints'' end,'',script,print~''),</l14><l15>concat(''formnot,'',case when fn.fns&gt;0 then ''View Notifications'' else ''Add Notifications'' end,'',script,notifications_active~''),</l15><l16>concat(''queue,'',case when oq.oqns&gt;0 then ''Queue listing'' else ''Add to Outbound queue'' end,'',script,playlist_add~''),</l16><l17>''condata,Connected forms,script,call_merge'') AxRowOptions,</l17><l18>b.cnt rules,p.pros 