mp" hint="Tasks" down=""/><x__head caption="User permissions" cat="txt" tlhw="7,5,24,75" parent="pnlButton" font="Tahoma,12,clWindowText,tfff" def="left" type="" align="none" color=""/></comps><row1 cat="sql"><a1>Task1</a1><a2><l0>select distinct a.axpermissionsid,b.username,concat(b.caption,''-('',b.sname,'')'') formcap,coalesce(a.allowcreate,''Yes'') allowcreate,coalesce(a.viewdlts,''All'')viewdlts,coalesce(editdlts,''All'') editdlts,</l0><l1>b.sname,concat(b.caption,''-('',b.sname,'')'') capui,''Form'' comptype,b.stype,</l1><l2>case b.stype when ''t'' then ''Form'' when ''i'' then ''Report'' when ''p'' then ''Page'' else null end stypeui,</l2><l3>case when b.stype=''t'' and (a.fromsource is null or a.fromsource=''U'' )then ''aperm,Add permission,script,build_circle'' end AxRowOptions,</l3><l4>case when b.stype=''t'' then ''Configure'' end perm,case when axuserrole=''All'' then ''User'' else ''Role - ''||axuserrole end axuserrole</l4><l5>from (</l5><l6>select b.axpermissionsid,b.axusername ,axuserrole ,b.formcap,coalesce(b.allowcreate,''Yes'') allowcreate,</l6><l7> case b.viewctrl when ''0'' then ''All'' </l7><l8> when ''1'' then ''View these fields - ''||view_flds </l8><l9> when ''2'' then ''View exclude these fields - ''||view_flds 	</l9><l10> when ''4'' then ''No access'' else ''All'' end viewdlts, </l10><l11> case b.editctrl when ''0'' then ''All'' </l11><l12> when ''1'' then ''Edit these fields - ''||edit_flds </l12><l13> when ''2'' then ''Edit exclude these fields ''||edit_flds</l13><l14> when ''4'' then ''No access'' else ''All'' end editdlts ,b.formtransid ,b.fromsource </l14><l15>from  axpermissions b join  axuserlevelgroups a on b.axuserrole = a.usergroup and a.username = :pusername</l15><l16>where  b.axuserrole !=''All''  </l16><l17>union all</l17><l18>select b.axpermissionsid,b.axusername ,b.axuserrole ,b.formcap,coalesce(b.allowcreate,''Yes'') allowcreate,</l18><l19> case b.viewctrl when ''0'' then ''All'' </l19><l20> when ''1'' then ''View these fields - ''||view_flds </l20><l21> when ''2'' then ''View exclude these fields - ''||view_flds </l21><l22> when ''4'' then ''No access'' else ''All'' end viewdlts, </l22><l23> case b.editctrl when ''0'' then ''All'' </l23><l24> when ''1'' then ''Edit these fields - ''||edit_flds </l24><l25> when ''2'' then ''Edit exclude these fields ''||edit_flds</l25><l26> when ''4'' then ''No access'' else ''All'' end editdlts ,b.formtransid,b.fromsource  </l26><l27>from  axpermissions b where  b.axuserrole =''All''  and b.axusername = :pusername </l27><l28>)a</l28><l29>right join (select distinct sname,caption,username,stype,groupname from vw_username_role_menu_access </l29><l30>where username=:pusername </l30><l31>and (stype =case :pstype when ''Form'' then ''t'' when ''Report'' then ''i'' when ''Page'' then ''p'' end or ''All'' = :pstype)</l31><l32>union all</l32><l33>select distinct sname,caption,username,stype,''All'' from vw_username_role_menu_access </l33><l34>where username=:pusername </l34><l35>and (stype =case :pstype when ''Form'' then ''t'' when ''Report'' then ''i'' when ''Page'' then ''p'' end or ''All'' = :pstype)</l35><l36>) b on b.sname = a.formtransid  and b.groupname = a.axuserrole </l36><l37>union all</l37><l38>select distinct a.axpermissionsid,a.username, b.sqlname formcap,''NA'' allowcreate,</l38><l39>coalesce(a.viewdlts,''All'')viewdlts,''NA'' editdlts,</l39><l40>sqlname sname,sqlname capui,''ADS'' comptype,null stype,''ADS'' stypeui,</l40><l41>case when (a.fromsource is null or a.fromsource=''U'' ) then ''aperm,Setup permission,script,build_circle'' end AxRowOptions,''Configure'' perm,groupname from</l41><l42>(select p.axpermissionsid,u.username username,p.axuserrole groupname, p.formcap,</l42><l43>case p.viewctrl when ''0'' then ''All'' </l43><l44> when ''1'' then ''View these fields - ''||view_flds </l44><l45> when ''2'' then ''View exclude these fields - ''||view_flds </l45><l46> when ''4'' then ''No access'' else ''All'' end viewdlts,p.fromsource</l46><l47>from axpermissions p join  axuserlevelgroups u on p.axuserrole = u.usergroup and u.username = :pusername</l47><l48>where  p.axuserrole !=''All'' and p.comptype =''ADS''</l48><l49>union all</l49><l50>select p.axpermissionsid,p.axusername,null, p.formcap,</l50><l51>case p.viewctrl when ''0'' then ''All'' </l51><l52> when ''1'' then ''View these fields - ''||view_flds </l52><l53> when ''2'' then ''View exclude these fields - ''||view_flds </l53><l54> when ''4'' then ''No access'' else ''All'' end viewdlts,p.fromsource</l54><l55>from axpermissions p </l55><l56>where  p.axuserrole =''All'' and p.comptype =''ADS'' and p.axusername = :pusername)a</l56><l57>right join(select a.sqlname,b.axpermissionsid from axdirectsql a left join axpermissions b on a.sqlname = b.formcap and b.comptype=''ADS''</l57><l58>    union all</l58><l59>    select a.sqlname,0 from axdirectsql a)b on a.formcap=b.sqlname and b.axpermissionsid=a.axpermissionsid</l59><l60>where (:pstype =''ADS'' or ''All'' = :pstype)</l60><l61>order by 3</l61></a2><a3></a3><a4>reportsql</a4></row1><pusername cat="params" ord="1"><a1>Task1</a1><a0>pusername</a0><a2>pusername</a2><a4>Character</a4><a9>false</a9><a6 sugg="false"></a6><a10></a10><a21>true</a21><a11></a11><a5>0</a5><a12>true</a12><a14>false</a14><a56></a56><a13>Accept</a13><a15></a15><a67>325</a67><a68>false</a68></pusername><psource cat="params" ord="2"><a1>Task1</a1><a0>psource</a0><a2>psource</a2><a4>Character</a4><a9>false</a9><a6 sugg="false"></a6><a10></a10><a21>true</a21><a11></a11><a5>0</a5><a12>false</a12><a14>false</a14><a56>U</a56><a13>Accept</a13><a15></a15><a67>325</a67><a68>false</a68></psource><pstype cat="params" ord="3"><a1>Task1</a1><a0>pstype</a0><a2>Menu type</a2><a4>Character</a4><a9>false</a9><a6 sugg="false"></a6><a10></a10><a21>false</a21><a11>select cnd,ord from 
